// ──────────────────────────────────────────────────
// AUTH
// ──────────────────────────────────────────────────
async function handleLogin(e) {
  e.preventDefault();
  const pass = document.getElementById('admin-pass').value;
  const stored = localStorage.getItem(PASSWORD_KEY) || DEFAULT_PASS;
  if (pass === stored) {
    document.getElementById('login-screen').classList.add('hidden');
    document.getElementById('dashboard').style.display = 'flex';
    await loadContent();
    // Open Dialogue AI tab by default
    const dlgBtn = document.querySelector('.nav-item[data-tab="dialogue"]');
    if (dlgBtn) switchTab('dialogue', dlgBtn);
    // Pre-fill guest name
    const guestField = document.getElementById('dlg-guest');
    if (guestField && !guestField.value) guestField.value = 'AlFalasi';
    showToast('✓ Welcome back, Dr. Esam!');
  } else {
    const err = document.getElementById('login-error');
    err.hidden = false;
    document.getElementById('admin-pass').value = '';
    showToast('Incorrect password. Please try again.', true);
  }
}

function logout() {
  showToast('You have been logged out.');
  setTimeout(() => {
    document.getElementById('dashboard').style.display = 'none';
    document.getElementById('login-screen').classList.remove('hidden');
    document.getElementById('admin-pass').value = '';
  }, 1000);
}

function changePassword() {
  const np = document.getElementById('s-new-pass').value.trim();
  const cp = document.getElementById('s-confirm-pass').value.trim();
  const msg = document.getElementById('pass-msg');
  msg.hidden = false;
  if (!np) { msg.textContent = 'Enter a new password.'; msg.className = 'msg error'; return; }
  if (np !== cp) { msg.textContent = 'Passwords do not match.'; msg.className = 'msg error'; return; }
  localStorage.setItem(PASSWORD_KEY, np);
  msg.textContent = '✓ Password updated successfully.';
  msg.className = 'msg';
  document.getElementById('s-new-pass').value = '';
  document.getElementById('s-confirm-pass').value = '';
}

// ──────────────────────────────────────────────────
// TAB NAVIGATION
// ──────────────────────────────────────────────────
function switchTab(tab, btn) {
  document.querySelectorAll('.nav-item').forEach(b => b.classList.remove('active'));
  document.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('tab-' + tab).classList.add('active');
  document.getElementById('tab-title').textContent = btn.textContent.replace(/^[^\w]+/, '').trim();

  // Load tab-specific data
  if (tab === 'requests') {
    loadServiceRequests();
  } else if (tab === 'analytics') {
    if (typeof initAnalytics === 'function') initAnalytics();
  } else if (tab === 'revenue') {
    if (typeof initRevenueReport === 'function') initRevenueReport();
  }
}

// ──────────────────────────────────────────────────
// LOAD CONTENT → fill form fields
// ──────────────────────────────────────────────────
async function loadContent() {
  let saved = null;

  // Try Supabase first
  try {
    const res = await fetch('/.netlify/functions/content-get');
    if (res.ok) {
      const data = await res.json();
      if (Object.keys(data).length > 0) {
        saved = data;
        console.log('Content loaded from Supabase');
      }
    }
  } catch (err) {
    console.warn('Failed to fetch from Supabase, falling back to localStorage:', err.message);
  }

  // Fall back to localStorage
  if (!saved) {
    const localSaved = localStorage.getItem(STORAGE_KEY);
    if (localSaved) {
      saved = JSON.parse(localSaved);
      console.log('Content loaded from localStorage');
    }
  }

  // Parse or use defaults
  content = saved ? (typeof saved === 'string' ? JSON.parse(saved) : saved) : JSON.parse(JSON.stringify(DEFAULTS));
  // Merge any missing keys from DEFAULTS
  content = deepMerge(JSON.parse(JSON.stringify(DEFAULTS)), content);

  fillSettings();
  fillHero();
  fillAbout();
  fillPlatforms();
  renderEpisodes();
  renderTiers();
}

