// ──────────────────────────────────────────────────
// EPISODES — Fetch from Supabase
// ──────────────────────────────────────────────────
let episodes = []; // Cache for episode list

async function renderEpisodes() {
  const list = document.getElementById('episodes-list');
  list.innerHTML = '<div style="text-align: center; padding: 20px;">Loading episodes...</div>';

  try {
    const response = await fetch('/.netlify/functions/episode-list');
    if (!response.ok) throw new Error('Failed to fetch episodes');
    episodes = await response.json();

    list.innerHTML = '';
    episodes.forEach((ep, i) => {
      const row = document.createElement('div');
      row.className = 'ep-row';
      row.innerHTML = `
        <img class="ep-thumb" src="${escHtml(ep.image_url)}" onerror="this.style.background='#333';this.removeAttribute('src')" alt="" />
        <div class="ep-info">
          <strong>${escHtml(ep.title)}</strong>
          <span>${escHtml(ep.guest_name || '')}</span>
        </div>
        <div class="ep-actions">
          <button class="ep-btn" data-edit="${i}">Edit</button>
          <button class="ep-btn delete" data-id="${ep.id}">Delete</button>
        </div>`;
      list.appendChild(row);
    });

    // Event delegation
    list.onclick = function(e) {
      const editBtn = e.target.closest('[data-edit]');
      const delBtn  = e.target.closest('[data-id]');
      if (editBtn) openEpDrawer(parseInt(editBtn.dataset.edit), episodes[parseInt(editBtn.dataset.edit)]);
      if (delBtn)  deleteEpisode(delBtn.dataset.id);
    };
  } catch (err) {
    list.innerHTML = `<div style="color: #e07070;">Error loading episodes: ${err.message}</div>`;
    console.error('renderEpisodes error:', err);
  }
}

let editingEpisode = null; // Current episode being edited
let pendingImageData = null; // Base64 image

function openEpDrawer(index = -1, ep = null) {
  editingEpisode = ep || null;
  pendingImageData = null;
  document.getElementById('ep-drawer-title').textContent = index === -1 ? 'Add Episode' : 'Edit Episode';
  document.getElementById('ep-image-file').value = '';
  set('ep-image-url', '');

  if (index === -1) {
    set('ep-title', '');
    set('ep-guest-name', '');
    set('ep-description', '');
    set('ep-youtube', '');
    set('ep-tiktok', '');
    // Hide preview, show placeholder
    document.getElementById('ep-preview').style.display = 'none';
    document.getElementById('upload-placeholder').style.display = 'flex';
  } else if (ep) {
    set('ep-title', ep.title || '');
    set('ep-guest-name', ep.guest_name || '');
    set('ep-description', ep.description || '');
    set('ep-youtube', ep.youtube || '');
    set('ep-tiktok', ep.tiktok || '');
    set('ep-image-url', ep.image_url || '');
    // Show preview if image exists
    if (ep.image_url) {
      document.getElementById('ep-preview').src = ep.image_url;
      document.getElementById('ep-preview').style.display = 'block';
      document.getElementById('upload-placeholder').style.display = 'none';
    } else {
      document.getElementById('ep-preview').style.display = 'none';
      document.getElementById('upload-placeholder').style.display = 'flex';
    }
  }
  document.getElementById('ep-drawer').style.display = 'block';
  document.getElementById('ep-drawer').scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function closeEpDrawer() {
  document.getElementById('ep-drawer').style.display = 'none';
  editingEpisode = null;
  pendingImageData = null;
}

function handleImageUpload(e) {
  const file = e.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(evt) {
    pendingImageData = evt.target.result;
    const preview = document.getElementById('ep-preview');
    const placeholder = document.getElementById('upload-placeholder');
    preview.src = pendingImageData;
    preview.style.display = 'block';
    placeholder.style.display = 'none';
  };
  reader.readAsDataURL(file);
}

async function saveEpisode() {
  const title = get('ep-title');
  if (!title) { showToast('Episode title is required', true); return; }

  // Priority: uploaded file > pasted URL > existing image
  let imageUrl = pendingImageData;
  if (!imageUrl) {
    const pastedUrl = get('ep-image-url');
    if (pastedUrl) {
      imageUrl = pastedUrl;
    } else if (editingEpisode && editingEpisode.image_url) {
      imageUrl = editingEpisode.image_url;
    }
  }

  const ep = {
    title: title,
    image_url: imageUrl || '',
    guest_name: get('ep-guest-name'),
    description: get('ep-description'),
    youtube: get('ep-youtube'),
    tiktok: get('ep-tiktok'),
    created_at: new Date().toISOString()
  };

  try {
    const response = await fetch('/.netlify/functions/episode-create', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(ep)
    });

    const data = await response.json();
    if (!response.ok) {
      showToast(`Error: ${data.error || 'Failed to save episode'}`, true);
      return;
    }

    closeEpDrawer();
    await renderEpisodes();
    showToast('✓ Episode saved successfully!');
  } catch (err) {
    showToast(`Error: ${err.message}`, true);
    console.error('saveEpisode error:', err);
  }
}

async function deleteEpisode(id) {
  if (!confirm('Delete this episode? This cannot be undone.')) return;

  try {
    const response = await fetch('/.netlify/functions/episode-delete', {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id })
    });

    if (!response.ok) {
      const data = await response.json();
      showToast(`Error: ${data.error || 'Failed to delete episode'}`, true);
      return;
    }

    await renderEpisodes();
    showToast('✓ Episode deleted successfully!');
  } catch (err) {
    showToast(`Error: ${err.message}`, true);
    console.error('deleteEpisode error:', err);
  }
}

