function renderTiers() {
  renderTierList('tiers-list', content.services.tiers);
  renderTierList('addons-list', content.services.addons);
  set('svc-cta-en', content.services.ctaEn);
  set('svc-cta-ar', content.services.ctaAr);
}

function renderTierList(containerId, items) {
  const list = document.getElementById(containerId);
  list.innerHTML = '';
  items.forEach((item, i) => {
    const row = document.createElement('div');
    row.className = 'tier-row';
    row.innerHTML = `
      <div>
        <label>Name (English)</label>
        <input type="text" value="${escHtml(item.emoji + ' ' + item.nameEn)}" data-field="nameEn" data-container="${containerId}" data-index="${i}" />
      </div>
      <div>
        <label>USD Price</label>
        <input type="number" value="${item.usd}" data-field="usd" data-container="${containerId}" data-index="${i}" />
      </div>
      <div>
        <label>AED Price</label>
        <input type="number" value="${item.aed}" data-field="aed" data-container="${containerId}" data-index="${i}" />
      </div>`;
    list.appendChild(row);
  });

  // Sync tier inputs back to content on change
  list.querySelectorAll('input').forEach(inp => {
    inp.addEventListener('input', () => {
      const idx = parseInt(inp.dataset.index);
      const field = inp.dataset.field;
      const arr = inp.dataset.container === 'tiers-list' ? content.services.tiers : content.services.addons;
      if (field === 'nameEn') {
        // strip leading emoji + space
        arr[idx].nameEn = inp.value.replace(/^[\p{Emoji}\s]+/u, '').trim();
      } else if (field === 'usd') {
        arr[idx].usd = parseFloat(inp.value) || 0;
      } else if (field === 'aed') {
        arr[idx].aed = parseFloat(inp.value) || 0;
      }
    });
  });
}

