// ──────────────────────────────────────────────────
// HELPERS
// ──────────────────────────────────────────────────
function get(id) {
  const el = document.getElementById(id);
  return el ? el.value.trim() : '';
}
function set(id, val) {
  const el = document.getElementById(id);
  if (el) el.value = val || '';
}
function escHtml(str) {
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function showToast(msg, isError = false) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast' + (isError ? ' error' : '');
  t.hidden = false;
  setTimeout(() => { t.hidden = true; }, 3500);
}
function deepMerge(target, source) {
  for (const key of Object.keys(source)) {
    if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
      if (!target[key]) target[key] = {};
      deepMerge(target[key], source[key]);
    } else {
      target[key] = source[key];
    }
  }
  return target;
}

// Toggle password-style field visibility (reusable)
function toggleFieldVisibility(fieldId, btn) {
  const input = document.getElementById(fieldId);
  if (!input) return;
  const show = input.type === 'password';
  input.type = show ? 'text' : 'password';
  const svg = btn.querySelector('svg');
  if (svg) svg.innerHTML = show
    ? `<path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/>`
    : `<path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>`;
}

// ──────────────────────────────────────────────────
// DIALOGUE AI TAB
// ──────────────────────────────────────────────────
(function initDialogue() {
  let currentScript = '';
  let currentMeta   = {};

  function dlgEl(id) { return document.getElementById(id); }

  function showStep(step) {
    dlgEl('dlg-step-inputs').style.display  = step === 'inputs'  ? 'block' : 'none';
    dlgEl('dlg-step-output').style.display  = step === 'output'  ? 'block' : 'none';
  }

  function showDlgError(msg) {
    const el = dlgEl('dlg-error');
    el.textContent = msg;
    el.style.display = 'block';
  }
  function hideDlgError() { dlgEl('dlg-error').style.display = 'none'; }

  async function fetchImages(subject) {
    try {
      const storedKey = content.settings?.claudeKey || '';
      const payload   = { subject };
      if (storedKey) payload.apiKey = storedKey;
      const res  = await fetch('/api/search-images', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();
      return data.images || [];
    } catch (_) { return []; }
  }

  async function callGenerateAPI(payload) {
    // Include stored Claude API key as fallback
    const storedKey = content.settings?.claudeKey || '';
    if (storedKey) payload.apiKey = storedKey;

    const res = await fetch('/api/generate-dialogue', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const text = await res.text();
    if (!text) throw new Error('Server timed out — please try again.');
    let data;
    try { data = JSON.parse(text); } catch (_) { throw new Error('Server error — please try again.'); }
    if (!res.ok) throw new Error(data.error || 'Generation failed');
    return data.script;
  }

  // Generate initial script
  async function onGenerate() {
    const hostName = dlgEl('dlg-host').value.trim();
    const guestName = dlgEl('dlg-guest').value.trim();
    const subject   = dlgEl('dlg-subject').value.trim();
    const duration  = dlgEl('dlg-duration').value;

    if (!hostName || !guestName || !subject) {
      showDlgError('Please fill in Host Name, Guest Name, and Topic before generating.');
      return;
    }
    hideDlgError();
    dlgEl('dlg-spinner').style.display = 'flex';
    dlgEl('dlg-generate-btn').disabled = true;

    try {
      const script = await callGenerateAPI({ hostName, guestName, subject, duration });
      currentScript = script;
      currentMeta   = { hostName, guestName, subject, duration };
      dlgEl('dlg-script-area').value = script;
      showStep('output');
      showToast('Script generated!');
    } catch (err) {
      showDlgError('Error: ' + err.message);
    } finally {
      dlgEl('dlg-spinner').style.display = 'none';
      dlgEl('dlg-generate-btn').disabled = false;
    }
  }

  // Regenerate with modifications
  async function onRegenerate() {
    const modifications = dlgEl('dlg-modify-input').value.trim();
    if (!modifications) { showToast('Please describe what you want changed.', true); return; }
    const script = dlgEl('dlg-script-area').value.trim();

    dlgEl('dlg-regen-spinner').style.display = 'flex';
    dlgEl('dlg-regenerate-btn').disabled = true;

    try {
      const newScript = await callGenerateAPI({ script, modifications });
      currentScript = newScript;
      dlgEl('dlg-script-area').value = newScript;
      dlgEl('dlg-modify-input').value = '';
      showToast('Script revised!');
    } catch (err) {
      showToast('Error: ' + err.message, true);
    } finally {
      dlgEl('dlg-regen-spinner').style.display = 'none';
      dlgEl('dlg-regenerate-btn').disabled = false;
    }
  }

  // Export .txt
  function exportTxt() {
    const script = dlgEl('dlg-script-area').value;
    const { subject = 'podcast', hostName = '', guestName = '', duration = '' } = currentMeta;
    const header = `PODCAST DIALOGUE SCRIPT\n${'='.repeat(40)}\nSubject:  ${subject}\nHost:     ${hostName}\nGuest:    ${guestName}\nDuration: ${duration}\nDate:     ${new Date().toLocaleDateString()}\n${'='.repeat(40)}\n\n`;
    const blob = new Blob([header + script + '\n\n— Generated by DrEsam Podcast Dialogue AI'], { type: 'text/plain' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dialogue_${subject.replace(/\s+/g,'_').toLowerCase()}.txt`;
    a.click();
    showToast('Text file downloaded!');
  }

  // Export .pdf using jsPDF
  async function exportPdf() {
    if (typeof window.jspdf === 'undefined' && typeof jsPDF === 'undefined') {
      showToast('PDF library not loaded yet — try again in a moment.', true);
      return;
    }
    const { jsPDF: JSPDF } = window.jspdf || { jsPDF };
    const script  = dlgEl('dlg-script-area').value;
    const { subject = 'Podcast Episode', hostName = 'Host', guestName = 'Guest', duration = '' } = currentMeta;

    // Fetch images before building PDF
    dlgEl('dlg-regen-spinner').style.display = 'flex';
    dlgEl('dlg-regen-spinner').querySelector('span').textContent = 'Fetching images…';
    const imgs = await fetchImages(subject);
    dlgEl('dlg-regen-spinner').style.display = 'none';
    dlgEl('dlg-regen-spinner').querySelector('span').textContent = 'Revising script…';

    const doc    = new JSPDF({ unit: 'mm', format: 'a4' });
    const gold   = [180, 140, 50];
    const dark   = [30, 30, 30];
    const mid    = [80, 80, 80];
    const light  = [130, 130, 130];
    const pageW  = doc.internal.pageSize.getWidth();
    const pageH  = 297;
    const margin = 18;
    const maxW   = pageW - margin * 2;
    let y        = 0;

    // Watermark (25% opacity, baked in) + full-color corner logo
    const logoWmB64   = '';
    const logoFullB64 = '';

    function addWatermark() {
      try {
        const sz = 160;
        doc.addImage('data:image/jpeg;base64,' + logoWmB64, 'JPEG', (pageW-sz)/2, (pageH-sz)/2, sz, sz);
      } catch (_) {}
    }
    function addCornerLogo() {
      try {
        doc.addImage('data:image/jpeg;base64,' + logoFullB64, 'JPEG', margin, 1, 18, 18);
      } catch (_) {}
    }

    // New page helper — white bg + top gold bar + watermark
    function newPage() {
      doc.addPage();
      doc.setFillColor(255, 255, 255);
      doc.rect(0, 0, pageW, pageH, 'F');
      doc.setFillColor(...gold);
      doc.rect(0, 0, pageW, 2.5, 'F');
      addWatermark();
      addCornerLogo();
      // Footer
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.setTextColor(...light);
      doc.text('Dr Esam Podcast — Dialogue Script', pageW / 2, pageH - 8, { align: 'center' });
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.2);
      doc.line(margin, pageH - 11, pageW - margin, pageH - 11);
    }

    // ── COVER PAGE ──────────────────────────────────
    doc.setFillColor(255, 255, 255);
    doc.rect(0, 0, pageW, pageH, 'F');

    // Gold top bar
    doc.setFillColor(...gold);
    doc.rect(0, 0, pageW, 6, 'F');

    // Watermark on cover — big, centered on page
    addWatermark();

    // Corner logo on cover
    addCornerLogo();

    // Title
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(24);
    doc.setTextColor(...dark);
    doc.text(subject, pageW / 2, 68, { align: 'center', maxWidth: maxW });

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(11);
    doc.setTextColor(...gold);
    doc.text('EPISODE SCRIPT', pageW / 2, 78, { align: 'center' });

    doc.setDrawColor(...gold);
    doc.setLineWidth(0.5);
    doc.line(margin + 20, 84, pageW - margin - 20, 84);

    doc.setFontSize(11);
    doc.setTextColor(...dark);
    doc.text(`Host:      ${hostName}`,  margin, 96);
    doc.text(`Guest:     ${guestName}`, margin, 106);
    doc.text(`Duration:  ${duration}`,  margin, 116);
    doc.text(`Date:      ${new Date().toLocaleDateString()}`, margin, 126);

    // Cover image
    if (imgs[0]) {
      try {
        const iH = 80, iY = 140;
        doc.addImage(`data:image/${imgs[0].type};base64,${imgs[0].base64}`, imgs[0].type.toUpperCase(), margin, iY, maxW, iH);
        doc.setFont('helvetica', 'italic'); doc.setFontSize(8); doc.setTextColor(...light);
        doc.text(imgs[0].caption || imgs[0].title || '', pageW / 2, iY + iH + 5, { align: 'center' });
      } catch (_) {}
    }

    doc.setFont('helvetica', 'normal'); doc.setFontSize(9); doc.setTextColor(...light);
    doc.text('Generated by DrEsam Podcast Dialogue AI', pageW / 2, pageH - 10, { align: 'center' });
    doc.setDrawColor(...gold); doc.setLineWidth(0.2);
    doc.line(margin, pageH - 13, pageW - margin, pageH - 13);

    // ── PAGE 2: OVERVIEW + DIALOGUE ────────────────
    newPage();
    y = 18;

    if (imgs[1]) {
      try {
        doc.setFont('helvetica', 'bold'); doc.setFontSize(12); doc.setTextColor(...gold);
        doc.text(`${subject} — At a Glance`, margin, y); y += 6;
        const iH = 65;
        doc.addImage(`data:image/${imgs[1].type};base64,${imgs[1].base64}`, imgs[1].type.toUpperCase(), margin, y, maxW, iH);
        doc.setFont('helvetica', 'italic'); doc.setFontSize(8); doc.setTextColor(...light);
        doc.text(imgs[1].caption || imgs[1].title || '', pageW / 2, y + iH + 4, { align: 'center' });
        y += iH + 12;
        doc.setDrawColor(...gold); doc.setLineWidth(0.3);
        doc.line(margin, y, pageW - margin, y); y += 8;
      } catch (_) {}
    }

    if (imgs[2]) {
      try {
        doc.setFont('helvetica', 'bold'); doc.setFontSize(11); doc.setTextColor(...dark);
        doc.text(`Reference: ${subject}`, margin, y); y += 5;
        const iH = 55;
        doc.addImage(`data:image/${imgs[2].type};base64,${imgs[2].base64}`, imgs[2].type.toUpperCase(), margin, y, maxW, iH);
        doc.setFont('helvetica', 'italic'); doc.setFontSize(8); doc.setTextColor(...light);
        doc.text(imgs[2].caption || imgs[2].title || '', pageW / 2, y + iH + 4, { align: 'center' });
        y += iH + 14;
      } catch (_) {}
    }

    // ── DIALOGUE LINES ─────────────────────────────
    for (const line of script.split('\n')) {
      const trimmed = line.trim();

      if (y > 270) { newPage(); y = 18; }
      if (!trimmed) { y += 4; continue; }

      if (trimmed.startsWith('===') && trimmed.endsWith('===')) {
        y += 4;
        doc.setFont('helvetica', 'bold'); doc.setFontSize(12); doc.setTextColor(...gold);
        doc.text(trimmed.replace(/===/g, '').trim(), margin, y);
        doc.setDrawColor(...gold); doc.setLineWidth(0.3);
        doc.line(margin, y + 2, pageW - margin, y + 2);
        y += 10;

      } else if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
        doc.setFont('helvetica', 'italic'); doc.setFontSize(9); doc.setTextColor(...light);
        doc.text(trimmed, margin + 4, y); y += 6;

      } else if (/^(HOST|GUEST)\s*\(/.test(trimmed)) {
        const match = trimmed.match(/^(HOST|GUEST)\s*\(([^)]+)\):\s*(.*)/s);
        if (match) {
          const isHost  = match[1] === 'HOST';
          const label   = `${match[1]} (${match[2]}): `;
          const labelC  = isHost ? gold : [60, 60, 140];
          const textC   = dark;
          doc.setFont('helvetica', 'bold'); doc.setFontSize(10); doc.setTextColor(...labelC);
          const labelW  = doc.getTextWidth(label);
          doc.text(label, margin, y);
          doc.setFont('helvetica', 'normal'); doc.setTextColor(...textC);
          const rest    = doc.splitTextToSize(match[3], maxW - labelW);
          if (rest[0]) doc.text(rest[0], margin + labelW, y);
          y += 6;
          for (let i = 1; i < rest.length; i++) {
            if (y > 270) { newPage(); y = 18; }
            doc.text(rest[i], margin, y); y += 6;
          }
          y += 2;
        }
      } else {
        doc.setFont('helvetica', 'normal'); doc.setFontSize(10); doc.setTextColor(...dark);
        const wrapped = doc.splitTextToSize(trimmed, maxW);
        for (const wl of wrapped) {
          if (y > 270) { newPage(); y = 18; }
          doc.text(wl, margin, y); y += 6;
        }
      }
    }

    doc.save(`dialogue_${subject.replace(/\s+/g,'_').toLowerCase()}.pdf`);
    showToast('PDF downloaded!');
  }

  // Export .docx using the docx browser library
  async function exportDocx() {
    if (typeof docx === 'undefined') {
      showToast('docx library not loaded yet — try again in a moment.', true);
      return;
    }
    const script  = dlgEl('dlg-script-area').value;
    const { subject = 'Podcast Episode', hostName = 'Host', guestName = 'Guest', duration = '' } = currentMeta;

    // Fetch images
    dlgEl('dlg-regen-spinner').style.display = 'flex';
    dlgEl('dlg-regen-spinner').querySelector('span').textContent = 'Fetching images…';
    const imgs = await fetchImages(subject);
    dlgEl('dlg-regen-spinner').style.display = 'none';
    dlgEl('dlg-regen-spinner').querySelector('span').textContent = 'Revising script…';

    // Watermark embedded
    const _wmB64 = '';
    const _wmBin = atob(_wmB64);
    const _wmArr = new Uint8Array(_wmBin.length);
    for (let i=0;i<_wmBin.length;i++) _wmArr[i]=_wmBin.charCodeAt(i);
    const logoBytes = _wmArr;

    const lines    = script.split('\n');
    const children = [];
    const { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ImageRun, Header, Footer } = docx;

    function makeImageParagraph(img, captionText) {
      const bytes = Uint8Array.from(atob(img.base64), c => c.charCodeAt(0));
      const paras = [];
      paras.push(new Paragraph({
        children: [ new ImageRun({ data: bytes, transformation: { width: 550, height: 300 }, type: img.type === 'png' ? 'png' : 'jpg' }) ],
        alignment: AlignmentType.CENTER
      }));
      paras.push(new Paragraph({
        children: [ new TextRun({ text: captionText || img.caption || img.title || '', italics: true, color: '888888', size: 18 }) ],
        alignment: AlignmentType.CENTER,
        spacing: { after: 200 }
      }));
      return paras;
    }

    // Header with logo watermark
    const headerChildren = [];
    if (logoBytes) {
      headerChildren.push(new Paragraph({
        children: [ new ImageRun({ data: logoBytes, transformation: { width: 40, height: 40 }, type: 'jpg' }) ],
        alignment: AlignmentType.RIGHT
      }));
    }
    headerChildren.push(new Paragraph({
      children: [ new TextRun({ text: 'Dr Esam Podcast — Episode Script', color: 'C9A84C', size: 18 }) ],
      alignment: AlignmentType.RIGHT
    }));

    const footerPara = new Paragraph({
      children: [ new TextRun({ text: 'Generated by DrEsam Podcast Dialogue AI', italics: true, color: '888888', size: 16 }) ],
      alignment: AlignmentType.CENTER
    });

    // Cover
    children.push(new Paragraph({ text: `${subject}`, heading: HeadingLevel.TITLE, alignment: AlignmentType.CENTER }));
    if (logoBytes) {
      children.push(new Paragraph({
        children: [ new ImageRun({ data: logoBytes, transformation: { width: 80, height: 80 }, type: 'jpg' }) ],
        alignment: AlignmentType.CENTER,
        spacing: { before: 200, after: 200 }
      }));
    }
    children.push(new Paragraph({ children: [ new TextRun({ text: `Host: ${hostName}`, bold: true, size: 24 }) ] }));
    children.push(new Paragraph({ children: [ new TextRun({ text: `Guest: ${guestName}`, bold: true, size: 24 }) ] }));
    children.push(new Paragraph({ children: [ new TextRun({ text: `Duration: ${duration}`, size: 22 }) ] }));
    children.push(new Paragraph({ children: [ new TextRun({ text: `Date: ${new Date().toLocaleDateString()}`, size: 22 }) ] }));
    children.push(new Paragraph({ text: '' }));

    // Cover image
    if (imgs[0]) { try { makeImageParagraph(imgs[0], imgs[0].caption).forEach(p => children.push(p)); } catch (_) {} }

    children.push(new Paragraph({ border: { bottom: { style: 'single', size: 6, color: 'C9A84C' } }, text: '' }));
    children.push(new Paragraph({ text: '' }));

    // Overview image
    if (imgs[1]) {
      try {
        children.push(new Paragraph({ text: `${subject} — At a Glance`, heading: HeadingLevel.HEADING_2 }));
        makeImageParagraph(imgs[1], imgs[1].caption).forEach(p => children.push(p));
        children.push(new Paragraph({ text: '' }));
      } catch (_) {}
    }

    // Reference image before dialogue
    if (imgs[2]) {
      try {
        children.push(new Paragraph({ text: `Reference: ${subject}`, heading: HeadingLevel.HEADING_2 }));
        makeImageParagraph(imgs[2], imgs[2].caption).forEach(p => children.push(p));
        children.push(new Paragraph({ text: '' }));
      } catch (_) {}
    }

    // Script lines
    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) { children.push(new Paragraph({ text: '' })); continue; }

      if (trimmed.startsWith('===') && trimmed.endsWith('===')) {
        // Section header
        children.push(new Paragraph({
          text: trimmed.replace(/===/g,'').trim(),
          heading: HeadingLevel.HEADING_2,
          spacing: { before: 240, after: 120 }
        }));
      } else if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
        // Pacing cue
        children.push(new Paragraph({
          children: [ new TextRun({ text: trimmed, italics: true, color: '888888', size: 20 }) ]
        }));
      } else if (/^(HOST|GUEST)\s*\(/.test(trimmed)) {
        // Dialogue line — split label from text
        const match = trimmed.match(/^(HOST|GUEST)\s*\(([^)]+)\):\s*(.*)/s);
        if (match) {
          children.push(new Paragraph({
            children: [
              new TextRun({ text: `${match[1]} (${match[2]}): `, bold: true, size: 24 }),
              new TextRun({ text: match[3], size: 24 })
            ],
            spacing: { after: 100 }
          }));
        } else {
          children.push(new Paragraph({ text: trimmed }));
        }
      } else {
        children.push(new Paragraph({ text: trimmed }));
      }
    }

    // Footer
    children.push(new Paragraph({ text: '' }));
    children.push(new Paragraph({
      children: [ new TextRun({ text: 'Generated by DrEsam Podcast Dialogue AI', italics: true, color: '888888', size: 18 }) ],
      alignment: AlignmentType.CENTER
    }));

    const doc = new Document({
      sections: [{
        properties: {},
        headers: { default: new Header({ children: headerChildren }) },
        footers: { default: new Footer({ children: [footerPara] }) },
        children
      }]
    });
    const blob = await Packer.toBlob(doc);
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dialogue_${subject.replace(/\s+/g,'_').toLowerCase()}.docx`;
    a.click();
    showToast('Word document downloaded!');
  }

  // Wire up events after DOM ready
  document.addEventListener('DOMContentLoaded', () => {
    dlgEl('dlg-generate-btn') .addEventListener('click', onGenerate);
    dlgEl('dlg-regenerate-btn').addEventListener('click', onRegenerate);
    dlgEl('dlg-export-txt')   .addEventListener('click', exportTxt);
    dlgEl('dlg-export-docx')  .addEventListener('click', exportDocx);
    dlgEl('dlg-export-pdf')   .addEventListener('click', exportPdf);
    dlgEl('dlg-new-btn')      .addEventListener('click', () => {
      showStep('inputs');
      dlgEl('dlg-script-area').value = '';
      dlgEl('dlg-modify-input').value = '';
      currentScript = '';
      currentMeta   = {};
    });
    showStep('inputs');
  });
})();


// ──────────────────────────────────────────────────
// SERVICE REQUESTS MANAGEMENT
// ──────────────────────────────────────────────────
async function loadServiceRequests() {
  console.log('loadServiceRequests called');
  const list = document.getElementById('requests-list');
  if (!list) {
    console.error('requests-list element not found!');
    return;
  }

  list.innerHTML = '<p style="text-align:center; padding:20px;">Loading requests...</p>';

  try {
    const res = await fetch('/.netlify/functions/service-requests-list');
    console.log('Fetch response:', res.status, res.ok);
    if (!res.ok) throw new Error('Failed to fetch requests');
    const requests = await res.json();
    console.log('Fetched requests:', requests.length, 'items');

    if (!requests || requests.length === 0) {
      list.innerHTML = '<p style="text-align:center; padding:20px; color:#999;">No service requests yet.</p>';
      return;
    }

    list.innerHTML = requests.map(req => `
      <div class="request-card">
        <div class="request-info">
          <div class="request-header">
            <div>
              <div class="request-name">${escapeHtml(req.first_name)} ${escapeHtml(req.last_name)}</div>
              <div class="request-detail"><strong>Email:</strong> ${escapeHtml(req.email)}</div>
            </div>
            <div class="request-status status-${req.status || 'discussion'}">${(req.status || 'discussion').toUpperCase()}</div>
          </div>
          <div class="request-service">${escapeHtml(req.service_name || 'Unknown Service')}</div>
          <div class="request-detail"><strong>Date:</strong> ${new Date(req.created_at).toLocaleDateString()}</div>
          ${req.price_aed ? `<div class="request-price">💰 ${req.price_aed.toLocaleString()} AED</div>` : ''}
        </div>
        <div class="request-actions">
          <button class="btn-status ${(req.status || 'discussion') !== 'discussion' ? 'disabled' : ''}" 
                  onclick="updateRequestStatus('${req.id}', 'agreed')"
                  ${(req.status || 'discussion') !== 'discussion' ? 'disabled' : ''}>
            → Agreed
          </button>
          <button class="btn-status ${(req.status || 'discussion') === 'done' ? 'disabled' : ''}" 
                  onclick="updateRequestStatus('${req.id}', 'done')"
                  ${(req.status || 'discussion') === 'done' ? 'disabled' : ''}>
            ✓ Done
          </button>
        </div>
      </div>
    `).join('');
  } catch (err) {
    console.error('Load requests error:', err);
    list.innerHTML = `<p style="color:#f44336; padding:20px;">Error loading requests: ${err.message}</p>`;
  }
}

async function updateRequestStatus(id, status) {
  console.log('updateRequestStatus called:', { id, status });
  try {
    const res = await fetch('/.netlify/functions/update-request-status', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id, status })
    });

    console.log('Update response:', res.status, res.ok);
    if (!res.ok) throw new Error('Failed to update status');

    showToast(`✓ Status updated to ${status}`);
    // Small delay to ensure database update completes
    console.log('Calling loadServiceRequests after 300ms');
    setTimeout(() => {
      console.log('Reloading service requests...');
      loadServiceRequests();
    }, 300);
  } catch (err) {
    showToast(`Error: ${err.message}`, true);
    console.error('Update status error:', err);
  }
}
